/// Builds a render pipeline for pass 0 using generated fixed-function state.
pub fn create_render_pipeline_pass0(
    device: &wgpu::Device,
    label: &str,
    layout: &wgpu::PipelineLayout,
    surface_format: wgpu::TextureFormat,
    depth_format: Option<wgpu::TextureFormat>,
    variant: &VariantKey,
    vertex_layout_override: Option<&[wgpu::VertexBufferLayout]>,
    material: &Material,
) -> wgpu::RenderPipeline {
    let vertex_buffers: &[wgpu::VertexBufferLayout] = match vertex_layout_override { Some(b) => b, None => VERTEX_BUFFER_LAYOUTS_PASS0 };
    let module = device.create_shader_module(wgpu::ShaderModuleDescriptor {
        label: Some("PBSSpecular"),
        source: shader_source_forward(),
    });
    let vertex_opts = pipeline_compilation_options_pass0_vertex(variant);
    let fragment_opts = pipeline_compilation_options_pass0_fragment(variant);
    device.create_render_pipeline(&wgpu::RenderPipelineDescriptor {
        label: Some(label),
        layout: Some(layout),
        vertex: wgpu::VertexState {
            module: &module,
            entry_point: Some("vertBase"),
            buffers: vertex_buffers,
            compilation_options: vertex_opts,
        },
        fragment: Some(wgpu::FragmentState {
            module: &module,
            entry_point: Some("fragBase"),
            targets: &[color_target_state_pass0(material, surface_format)],
            compilation_options: fragment_opts,
        }),
        primitive: primitive_state_pass0(material),
        depth_stencil: depth_format.map(|df| depth_stencil_state_pass0(material, df)),
        multisample: wgpu::MultisampleState::default(),
        multiview_mask: None,
        cache: None,
    })
}

