/// Dispatches to `create_render_pipeline_passN` by index. Panics if `pass_index` is out of range.
#[allow(clippy::too_many_arguments)]
pub fn create_render_pipeline(
    device: &wgpu::Device,
    label: &str,
    layout: &wgpu::PipelineLayout,
    surface_format: wgpu::TextureFormat,
    depth_format: Option<wgpu::TextureFormat>,
    variant: &VariantKey,
    pass_index: usize,
    vertex_layout_override: Option<&[wgpu::VertexBufferLayout]>,
    material: &Material,
) -> wgpu::RenderPipeline {
    match pass_index {
        0 => create_render_pipeline_pass0(device, label, layout, surface_format, depth_format, variant, vertex_layout_override, material),
        1 => create_render_pipeline_pass1(device, label, layout, surface_format, depth_format, variant, vertex_layout_override, material),
        2 => create_render_pipeline_pass2(device, label, layout, surface_format, depth_format, variant, vertex_layout_override, material),
        3 => create_render_pipeline_pass3(device, label, layout, surface_format, depth_format, variant, vertex_layout_override, material),
        _ => panic!("invalid pass_index for this shader module"),
    }
}
